#include<bits/stdc++.h>
using namespace std;
__int128 a[1000010],b[1000010],c[1000010];
__int128 exgcd(__int128 a,__int128 b,__int128 &x,__int128 &y)
{
    if(b==0)
    {
        x=1;
        y=0;
        return a;
    }
    __int128 g=exgcd(b,a%b,x,y);
    __int128 tx=x;
    x=y;
    y=tx-(a/b)*y;
    return g;
}
int main()
{
    int n;
    scanf("%d",&n);
    __int128 sum=1;
    for(int i=1;i<=n;i++)
    {
        long long A;
        scanf("%lld",&A);
        a[i]=A;
    }
    for(int i=1;i<=n;i++)
    {
        long long B;
        scanf("%lld",&B);
        b[i]=B;
        a[i]=(a[i]%b[i]+b[i])%b[i];
        sum=sum*b[i];
    }
    __int128 ans=0;
    for(int i=1;i<=n;i++)
    {
        __int128 m=sum/::b[i],b,y;
        exgcd(m,::b[i],b,y);
        ans=(ans+a[i]*m%sum*b%sum)%sum;
    }
    printf("%lld",(long long)((ans%sum+sum)%sum));
    return 0;
}
